"""
Minimal roman numeral conversion helpers compatible with the ``roman`` package.
"""

from __future__ import annotations

import re


class RomanError(Exception):
    """Base class for roman conversion errors."""


class OutOfRangeError(RomanError):
    """Raised when an integer cannot be represented as a roman numeral."""


class NotIntegerError(RomanError):
    """Raised when conversion input is not an integer."""


class InvalidRomanNumeralError(RomanError):
    """Raised when text is not a valid roman numeral."""


_roman_numeral_map = (
    ("M", 1000),
    ("CM", 900),
    ("D", 500),
    ("CD", 400),
    ("C", 100),
    ("XC", 90),
    ("L", 50),
    ("XL", 40),
    ("X", 10),
    ("IX", 9),
    ("V", 5),
    ("IV", 4),
    ("I", 1),
)

romanNumeralPattern = re.compile(
    r"""^
        M{0,4}
        (CM|CD|D?C{0,3})
        (XC|XL|L?X{0,3})
        (IX|IV|V?I{0,3})
        $
    """,
    re.VERBOSE,
)


def toRoman(number: int) -> str:
    if not isinstance(number, int):
        raise NotIntegerError("non-integers can not be converted")
    if number <= 0 or number >= 5000:
        raise OutOfRangeError("number out of range (must be 1..4999)")

    result = []
    remaining = number
    for numeral, integer in _roman_numeral_map:
        while remaining >= integer:
            result.append(numeral)
            remaining -= integer
    return "".join(result)


def fromRoman(numeral: str) -> int:
    if not isinstance(numeral, str):
        raise InvalidRomanNumeralError("input must be a string")
    if numeral == "":
        raise InvalidRomanNumeralError("input can not be blank")
    if not romanNumeralPattern.match(numeral):
        raise InvalidRomanNumeralError(f"invalid roman numeral: {numeral}")

    index = 0
    result = 0
    text = numeral.upper()
    for roman_text, integer in _roman_numeral_map:
        while text[index : index + len(roman_text)] == roman_text:
            result += integer
            index += len(roman_text)
    return result
